  /// Builds a web-compatible URL for sharing.
  ///
  /// Uses a hypothetical web domain for universal link support.
  static Uri buildWebUri({
    required String moduleId,
    required Map<String, Object> params,
    required FractalViewState view,
  }) {
    final customUri = buildUri(moduleId: moduleId, params: params, view: view);
    return Uri(
      scheme: 'https',
      host: 'fractalforge.app',
      path: '/view',
      queryParameters: customUri.queryParameters,
    );
  }

  static double? _parseBoundedDouble(
      String? v, double min, double max, String paramName) {
    if (v == null) return null;
    final d = double.tryParse(v);
    if (d == null || d.isNaN || d.isInfinite) {
      if (kDebugMode)
        debugPrint('DeepLink: invalid value for "$paramName": "$v" — ignoring');
      return null;
    }
    final clamped = d.clamp(min, max);
    if (clamped != d) {
      if (kDebugMode)
        debugPrint(
            'DeepLink: "$paramName" value $d out of [$min, $max] — clamped to $clamped');
    }
    return clamped;
  }

  static int? _parseBoundedInt(String? v, int min, int max, String paramName) {
    if (v == null) return null;
    final i = int.tryParse(v);
    if (i == null) {
      if (kDebugMode)
        debugPrint('DeepLink: invalid value for "$paramName": "$v" — ignoring');
      return null;
    }
    final clamped = i.clamp(min, max);
    if (clamped != i) {
      if (kDebugMode)
        debugPrint(
            'DeepLink: "$paramName" value $i out of [$min, $max] — clamped to $clamped');
    }
    return clamped;
  }

  static String _formatDouble(
    double value, {
    bool preservePrecision = false,
    double compactTolerance = 0.0,
  }) {
    // Keep integer-looking values compact without truncating significant deep-zoom
    // view coordinates that need more than six decimal places to round-trip.
    if (value == value.truncateToDouble()) {
      return value.toInt().toString();
    }

    final compactFixed =
        value.toStringAsFixed(6).replaceAll(RegExp(r'\.?0+$'), '');
    final compactValue = double.tryParse(compactFixed);
    final compactWithinTolerance = compactValue != null &&
        compactTolerance > 0.0 &&
        (compactValue - value).abs() <= compactTolerance;
    if (!preservePrecision || compactValue == value || compactWithinTolerance) {
      return compactFixed;
    }

    return value.toString();
  }

  static void _addBoundedDoubleQueryParam(
    Map<String, String> queryParams,
    _BoundedDoubleQueryParam param,
    Object? value, {
    bool preservePrecision = false,
    double compactTolerance = 0.0,
  }) {
    final formatted = param.format(
      value,
      preservePrecision: preservePrecision,
      compactTolerance: compactTolerance,
    );
    if (formatted != null) {
      queryParams[param.name] = formatted;
    }
  }

  static void _addNonDefaultBoundedDoubleQueryParam(
    Map<String, String> queryParams,
    _BoundedDoubleQueryParam param,
    Object? value, {
    double defaultValue = 0.0,
    bool preservePrecision = false,
    double compactTolerance = 0.0,
  }) {
    final parsed = _tryFiniteDouble(value);
    if (parsed == null || parsed == defaultValue) return;
    _addBoundedDoubleQueryParam(
      queryParams,
      param,
      parsed,
      preservePrecision: preservePrecision,
      compactTolerance: compactTolerance,
    );
  }

  static void _addBoundedIntQueryParam(
    Map<String, String> queryParams,
    _BoundedIntQueryParam param,
    Object? value,
  ) {
    final formatted = param.format(value);
    if (formatted != null) {
      queryParams[param.name] = formatted;
    }
  }

  static double? _tryFiniteDouble(Object? value) {
    final parsed = switch (value) {
      double v => v,
      int v => v.toDouble(),
      String v => double.tryParse(v),
      _ => null,
    };
    if (parsed == null || parsed.isNaN || parsed.isInfinite) {
      return null;
    }
    return parsed;
  }

  /// Disposes of the service and closes the stream.
  void dispose() {
    _linkController.close();
  }
}

import 'package:shared_preferences/shared_preferences.dart';
import 'package:flutter_fractals/core/models/fractal_preset.dart';

class PresetStore {
  final SharedPreferences _prefs;

  PresetStore._(this._prefs);

  static Future<PresetStore> create() async {
    final prefs = await SharedPreferences.getInstance();
    return PresetStore._(prefs);
  }

  Future<List<FractalPreset>> loadUserPresets(String moduleId) async {
    final payload = _prefs.getString(_key(moduleId));
    return FractalPreset.listFromPrefs(payload);
  }

  Future<void> saveUserPreset(FractalPreset preset) async {
    final presets = await loadUserPresets(preset.moduleId);
    // Check for duplicate ID and replace if exists
    final existingIndex = presets.indexWhere((p) => p.id == preset.id);
    final List<FractalPreset> updated;
    if (existingIndex >= 0) {
      // Replace existing preset with same ID
      updated = [...presets];
      updated[existingIndex] = preset;
    } else {
      // Add new preset
      updated = [...presets, preset];
    }
    await _prefs.setString(_key(preset.moduleId), FractalPreset.listToPrefs(updated));
  }

  Future<void> deleteUserPreset(String moduleId, String presetId) async {
    final presets = await loadUserPresets(moduleId);
    final updated = presets.where((preset) => preset.id != presetId).toList();
    await _prefs.setString(_key(moduleId), FractalPreset.listToPrefs(updated));
  }

  Future<void> updatePreset(String moduleId, String presetId, {required String name}) async {
    final presets = await loadUserPresets(moduleId);
    final index = presets.indexWhere((p) => p.id == presetId);
    if (index < 0) return;
    final updated = [...presets];
    updated[index] = presets[index].copyWith(name: name);
    await _prefs.setString(_key(moduleId), FractalPreset.listToPrefs(updated));
  }

  String _key(String moduleId) => 'user_presets_$moduleId';
}

import 'package:flutter_test/flutter_test.dart';
import 'package:shared_preferences/shared_preferences.dart';
import 'package:vector_math/vector_math.dart';
import 'package:flutter_fractals/core/services/preset_store.dart';
import 'package:flutter_fractals/core/models/fractal_preset.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';

FractalPreset _makePreset(String id, String moduleId, {String name = 'Test', bool isBuiltIn = false}) {
  return FractalPreset(
    id: id,
    moduleId: moduleId,
    name: name,
    params: {'iterations': 100},
    view: FractalViewState(
      pan: Vector2(0.0, 0.0),
      zoom: 1.0,
      rotation: Vector3.zero(),
    ),
    createdAt: DateTime.utc(2024, 1, 1),
    isBuiltIn: isBuiltIn,
  );
}

void main() {
  group('PresetStore', () {
    setUp(() {
      TestWidgetsFlutterBinding.ensureInitialized();
      SharedPreferences.setMockInitialValues({});
    });

    test('create() factory returns a valid store', () async {
      final store = await PresetStore.create();
      expect(store, isNotNull);
    });

    test('loadUserPresets returns empty list for unknown module', () async {
      final store = await PresetStore.create();
      final presets = await store.loadUserPresets('unknown_module');
      expect(presets, isEmpty);
    });

    test('saveUserPreset persists preset and loadUserPresets returns it', () async {
      final store = await PresetStore.create();
      final preset = _makePreset('p1', 'mandelbrot', name: 'My Preset');

      await store.saveUserPreset(preset);
      final loaded = await store.loadUserPresets('mandelbrot');

      expect(loaded, hasLength(1));
      expect(loaded.first.id, equals('p1'));
      expect(loaded.first.name, equals('My Preset'));
      expect(loaded.first.moduleId, equals('mandelbrot'));
    });

    test('loadUserPresets for a different module returns empty list', () async {
      final store = await PresetStore.create();
      await store.saveUserPreset(_makePreset('p1', 'mandelbrot'));

      final loaded = await store.loadUserPresets('julia');
      expect(loaded, isEmpty);
    });

    test('deleteUserPreset removes the preset', () async {
      final store = await PresetStore.create();
      await store.saveUserPreset(_makePreset('p1', 'mandelbrot'));
      await store.saveUserPreset(_makePreset('p2', 'mandelbrot'));

      await store.deleteUserPreset('mandelbrot', 'p1');
      final loaded = await store.loadUserPresets('mandelbrot');

      expect(loaded, hasLength(1));
      expect(loaded.first.id, equals('p2'));
    });

    test('deleteUserPreset on non-existent id leaves list unchanged', () async {
      final store = await PresetStore.create();
      await store.saveUserPreset(_makePreset('p1', 'mandelbrot'));

      await store.deleteUserPreset('mandelbrot', 'does-not-exist');
      final loaded = await store.loadUserPresets('mandelbrot');

      expect(loaded, hasLength(1));
    });

    test('saveUserPreset replaces preset with same id', () async {
      final store = await PresetStore.create();
      await store.saveUserPreset(_makePreset('p1', 'mandelbrot', name: 'Original'));
      await store.saveUserPreset(_makePreset('p1', 'mandelbrot', name: 'Updated'));

      final loaded = await store.loadUserPresets('mandelbrot');
      expect(loaded, hasLength(1));
      expect(loaded.first.name, equals('Updated'));
    });

    test('user presets are stored separately per module', () async {
      final store = await PresetStore.create();
      await store.saveUserPreset(_makePreset('p1', 'mandelbrot'));
      await store.saveUserPreset(_makePreset('p2', 'julia'));

      final mandelbrot = await store.loadUserPresets('mandelbrot');
      final julia = await store.loadUserPresets('julia');

      expect(mandelbrot, hasLength(1));
      expect(mandelbrot.first.id, equals('p1'));
      expect(julia, hasLength(1));
      expect(julia.first.id, equals('p2'));
    });

    test('user presets are separate from built-in presets (isBuiltIn flag preserved)', () async {
      final store = await PresetStore.create();
      final userPreset = _makePreset('user-1', 'mandelbrot', isBuiltIn: false);
      final builtIn = _makePreset('builtin-1', 'mandelbrot', isBuiltIn: true);

      await store.saveUserPreset(userPreset);
      await store.saveUserPreset(builtIn);

      final loaded = await store.loadUserPresets('mandelbrot');
      expect(loaded, hasLength(2));

      final userLoaded = loaded.firstWhere((p) => p.id == 'user-1');
      final builtInLoaded = loaded.firstWhere((p) => p.id == 'builtin-1');
      expect(userLoaded.isBuiltIn, isFalse);
      expect(builtInLoaded.isBuiltIn, isTrue);
    });

    test('updatePreset renames preset by id', () async {
      final store = await PresetStore.create();
      await store.saveUserPreset(_makePreset('p1', 'mandelbrot', name: 'Old Name'));

      await store.updatePreset('mandelbrot', 'p1', name: 'New Name');
      final loaded = await store.loadUserPresets('mandelbrot');

      expect(loaded.first.name, equals('New Name'));
    });

    test('updatePreset on non-existent id is a no-op', () async {
      final store = await PresetStore.create();
      await store.saveUserPreset(_makePreset('p1', 'mandelbrot', name: 'Original'));

      await store.updatePreset('mandelbrot', 'does-not-exist', name: 'Ghost');
      final loaded = await store.loadUserPresets('mandelbrot');

      expect(loaded.first.name, equals('Original'));
    });
  });
}

import 'dart:convert';

import 'package:flutter/foundation.dart';
import 'package:shared_preferences/shared_preferences.dart';
import 'package:flutter_fractals/core/models/fractal_palette.dart';

class PaletteStore {
  static const _key = 'user_palettes_v1';

  final SharedPreferences _prefs;

  PaletteStore._(this._prefs);

  static Future<PaletteStore> create() async {
    final prefs = await SharedPreferences.getInstance();
    return PaletteStore._(prefs);
  }

  List<FractalPalette> loadPalettes() {
    return _decodePalettePayload(_prefs.get(_key));
  }

  List<FractalPalette> _decodePalettePayload(Object? payload) {
    if (payload == null) return const [];
    if (payload is String) return _decodeLegacyPaletteArray(payload);
    if (payload is List) return _decodePaletteListPayload(payload);
    return const [];
  }

  List<FractalPalette> _decodePaletteListPayload(List<Object?> payload) {
    final encodedPalettes = <String>[];
    for (final entry in payload) {
      if (entry is! String) return const [];
      encodedPalettes.add(entry);
    }
    return _decodePaletteStringList(encodedPalettes);
  }

  List<FractalPalette> _decodePaletteStringList(List<String> encodedPalettes) {
    final palettes = <FractalPalette>[];
    for (final encoded in encodedPalettes) {
      final palette = _tryDecodePaletteString(encoded);
      if (palette != null && palette.id.isNotEmpty) palettes.add(palette);
    }
    return palettes;
  }

  FractalPalette? _tryDecodePaletteString(String encoded) {
    try {
      return FractalPalette.fromJsonString(encoded);
    } catch (e) {
      if (kDebugMode) debugPrint('[FF] skipping palette entry: $e');
      return null;
    }
  }

  List<FractalPalette> _decodeLegacyPaletteArray(String? payload) {
    if (payload == null || payload.trim().isEmpty) return const [];

    try {
      final decodedArr = (jsonDecode(payload) as List).cast<Map>();
      return decodedArr
          .map((m) => FractalPalette.fromJson(m.cast<String, Object?>()))
          .where((p) => p.id.isNotEmpty)
          .toList();
    } catch (e) {
      if (kDebugMode) debugPrint('[FF] silent catch: $e');
      return const [];
    }
  }

  Future<void> savePalettes(List<FractalPalette> palettes) async {
    final list = palettes.map((p) => p.toJsonString(pretty: false)).toList();
    await _prefs.setStringList(_key, list);
  }
}

import 'dart:convert';

import 'package:flutter_fractals/core/models/fractal_palette.dart';
import 'package:flutter_fractals/core/services/palette_store.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:shared_preferences/shared_preferences.dart';

void main() {
  setUp(() {
    TestWidgetsFlutterBinding.ensureInitialized();
    SharedPreferences.setMockInitialValues({});
  });

  group('PaletteStore', () {
    test('loadPalettes returns empty list when no data', () async {
      final store = await PaletteStore.create();
      final palettes = store.loadPalettes();
      expect(palettes, isEmpty);
    });

    test('savePalettes and loadPalettes round-trip', () async {
      final store = await PaletteStore.create();

      final palettes = [
        const FractalPalette(
          id: 'pal-1',
          name: 'Fire',
          stops: [
            FractalColorStop(position: 0.0, colorArgb: 0xFFFF0000),
            FractalColorStop(position: 1.0, colorArgb: 0xFFFFFF00),
          ],
        ),
        const FractalPalette(
          id: 'pal-2',
          name: 'Ocean',
          stops: [
            FractalColorStop(position: 0.0, colorArgb: 0xFF0000FF),
            FractalColorStop(position: 1.0, colorArgb: 0xFF00FFFF),
          ],
        ),
      ];

      await store.savePalettes(palettes);
      final loaded = store.loadPalettes();

      expect(loaded.length, 2);
      expect(loaded[0].id, 'pal-1');
      expect(loaded[0].name, 'Fire');
      expect(loaded[0].stops.length, 2);
      expect(loaded[0].stops[0].colorArgb, 0xFFFF0000);
      expect(loaded[0].stops[1].colorArgb, 0xFFFFFF00);

      expect(loaded[1].id, 'pal-2');
      expect(loaded[1].name, 'Ocean');
      expect(loaded[1].stops[0].colorArgb, 0xFF0000FF);
    });

    test('savePalettes and loadPalettes preserves stop positions', () async {
      final store = await PaletteStore.create();

      final palette = const FractalPalette(
        id: 'gradient',
        name: 'Gradient',
        stops: [
          FractalColorStop(position: 0.0, colorArgb: 0xFFFFFFFF),
          FractalColorStop(position: 0.5, colorArgb: 0xFF888888),
          FractalColorStop(position: 1.0, colorArgb: 0xFF000000),
        ],
      );

      await store.savePalettes([palette]);
      final loaded = store.loadPalettes();

      expect(loaded.length, 1);
      expect(loaded[0].stops[1].position, closeTo(0.5, 1e-9));
    });

    test('loadPalettes skips corrupted string-list entries', () async {
      final goodEntry = const FractalPalette(
        id: 'ok',
        name: 'Good',
        stops: [FractalColorStop(position: 0.0, colorArgb: 0xFFFFFFFF)],
      ).toJsonString(pretty: false);

      SharedPreferences.setMockInitialValues({
        'user_palettes_v1': <String>['not valid json {{{{', goodEntry],
      });

      final store = await PaletteStore.create();
      final palettes = store.loadPalettes();

      expect(palettes, hasLength(1));
      expect(palettes.single.id, 'ok');
    });

    test('loadPalettes loads legacy JSON array payloads', () async {
      SharedPreferences.setMockInitialValues({
        'user_palettes_v1': jsonEncode([
          const FractalPalette(
            id: 'legacy',
            name: 'Legacy',
            stops: [FractalColorStop(position: 0.0, colorArgb: 0xFFFFFFFF)],
          ).toJson(),
        ]),
      });

      final store = await PaletteStore.create();
      final palettes = store.loadPalettes();

      expect(palettes, hasLength(1));
      expect(palettes.single.id, 'legacy');
      expect(palettes.single.name, 'Legacy');
    });

    test('loadPalettes skips palettes with empty id', () async {
      // Use the List<String> primary path: two serialised palette JSON strings,
      // one with an empty id (should be filtered) and one with a valid id.
      final badEntry = const FractalPalette(
        id: '',
        name: 'Bad',
        stops: [],
      ).toJsonString(pretty: false);
      final goodEntry = const FractalPalette(
        id: 'ok',
        name: 'Good',
        stops: [],
      ).toJsonString(pretty: false);

      SharedPreferences.setMockInitialValues({
        'user_palettes_v1': <String>[badEntry, goodEntry],
      });

      final store = await PaletteStore.create();
      final palettes = store.loadPalettes();
      expect(palettes.length, 1);
      expect(palettes.first.id, 'ok');
    });

    test('savePalettes overwrites previous save', () async {
      final store = await PaletteStore.create();

      final first = [
        const FractalPalette(
          id: 'first',
          name: 'First',
          stops: [FractalColorStop(position: 0.0, colorArgb: 0xFFFF0000)],
        ),
      ];
      final second = [
        const FractalPalette(
          id: 'second',
          name: 'Second',
          stops: [FractalColorStop(position: 0.0, colorArgb: 0xFF00FF00)],
        ),
      ];

      await store.savePalettes(first);
      await store.savePalettes(second);
      final loaded = store.loadPalettes();

      expect(loaded.length, 1);
      expect(loaded.first.id, 'second');
    });

    test('savePalettes with empty list clears palettes', () async {
      final store = await PaletteStore.create();

      final palettes = [
        const FractalPalette(
          id: 'p1',
          name: 'P1',
          stops: [FractalColorStop(position: 0.0, colorArgb: 0xFFFFFFFF)],
        ),
      ];
      await store.savePalettes(palettes);
      await store.savePalettes([]);
      final loaded = store.loadPalettes();

      expect(loaded, isEmpty);
    });
  });
}

import 'dart:convert';
import 'package:flutter/foundation.dart';
import 'package:vector_math/vector_math.dart';
import 'fractal_view_state.dart';

FractalViewState _snapshotPresetView(FractalViewState view) {
  return FractalViewState(
    pan: view.pan,
    zoom: view.zoom,
    rotation: view.rotation,
  );
}

Map<String, Object> _snapshotPresetParams(Map<String, Object> params) {
  return Map<String, Object>.unmodifiable({
    for (final entry in params.entries)
      entry.key: _snapshotPresetParamValue(entry.value),
  });
}

Map<String, Object> _decodePresetParams(Map params) {
  final decoded = <String, Object>{};
  for (final entry in params.entries) {
    final key = entry.key;
    final value = entry.value;
    if (key == null || value == null) continue;
    decoded[key.toString()] = _snapshotPresetParamValue(value as Object);
  }
  return Map<String, Object>.unmodifiable(decoded);
}

Object _snapshotPresetParamValue(Object value) {
  if (value is List) {
    return List<Object?>.unmodifiable([
      for (final item in value)
        item is Object ? _snapshotPresetParamValue(item) : item,
    ]);
  }

  if (value is Map) {
    return Map<String, Object?>.unmodifiable({
      for (final entry in value.entries)
        entry.key.toString(): entry.value is Object
            ? _snapshotPresetParamValue(entry.value as Object)
            : entry.value,
    });
  }

  return value;
}

/// A saved configuration of fractal parameters and view state.
///
/// Presets allow users to save and restore specific fractal configurations,
/// including both the mathematical parameters (iterations, bailout, etc.)
/// and the view state (pan, zoom, rotation).
///
/// Presets can be:
/// - **Built-in**: Included with the app and read-only
/// - **User-created**: Saved by the user with custom thumbnails
///
/// Presets are serializable to JSON for persistent storage.
///
/// {@category Models}
///
/// Example:
/// ```dart
/// final preset = FractalPreset(
///   id: 'my-preset',
///   moduleId: 'mandelbrot',
///   name: 'Deep Zoom',
///   params: {'iterations': 200, 'colorScheme': 2},
///   view: FractalViewState(
///     pan: Vector2(-0.75, 0.1),
///     zoom: 50.0,
///     rotation: Vector3.zero(),
///   ),
///   createdAt: DateTime.now(),
/// );
/// ```
@immutable
class FractalPreset {
  /// Unique identifier for this preset.
  ///
  /// For built-in presets, use a pattern like 'module-name'.
  /// For user presets, typically a UUID.
  final String id;

  /// The fractal module this preset belongs to.
  ///
  /// Must match a [FractalModule.id] in the registry.
  /// Presets are only applicable to their target module.
  final String moduleId;

  /// User-visible name for this preset.
  ///
  /// Should be descriptive and unique within the module's presets.
  final String name;

  /// The fractal parameter values.
  ///
  /// Keys are parameter IDs (e.g., 'iterations', 'colorScheme').
  /// Values are typed according to [FractalParamType].
  final Map<String, Object> params;

  /// The view state (pan, zoom, rotation) for this preset.
  ///
  /// Defines the camera position and orientation when
  /// the preset is applied.
  final FractalViewState view;

  /// When this preset was created.
  ///
  /// Used for sorting and display purposes.
  final DateTime createdAt;

  /// Whether this is a built-in (read-only) preset.
  ///
  /// Built-in presets cannot be edited or deleted by the user.
  final bool isBuiltIn;

  /// Path to the preset's thumbnail image.
  ///
  /// For user presets, this is typically a file path to a
  /// captured PNG. Built-in presets may use asset paths.
  final String? thumbnailPath;

  /// Creates a new [FractalPreset] with the specified configuration.
  ///
  /// The supplied view vectors and parameter collections are snapshotted so a
  /// preset remains replayable even when callers mutate their originals.
  FractalPreset({
    required this.id,
    required this.moduleId,
    required this.name,
    required Map<String, Object> params,
    required FractalViewState view,
    required this.createdAt,
    this.isBuiltIn = false,
    this.thumbnailPath,
  })  : params = _snapshotPresetParams(params),
        view = _snapshotPresetView(view);

  /// Creates a copy of this preset with the given fields replaced.
  ///
  /// Useful for creating variations of existing presets. Because `null` means
  /// "keep the existing value" for optional fields, set [clearThumbnailPath]
  /// when a copy must remove an existing thumbnail.
  FractalPreset copyWith({
    String? id,
    String? moduleId,
    String? name,
    Map<String, Object>? params,
    FractalViewState? view,
    DateTime? createdAt,
    bool? isBuiltIn,
    String? thumbnailPath,
    bool clearThumbnailPath = false,
  }) {
    assert(
      !clearThumbnailPath || thumbnailPath == null,
      'thumbnailPath cannot be provided when clearThumbnailPath is true',
    );
    return FractalPreset(
      id: id ?? this.id,
      moduleId: moduleId ?? this.moduleId,
      name: name ?? this.name,
      params: params ?? this.params,
      view: view ?? this.view,
      createdAt: createdAt ?? this.createdAt,
      isBuiltIn: isBuiltIn ?? this.isBuiltIn,
      thumbnailPath:
          clearThumbnailPath ? null : thumbnailPath ?? this.thumbnailPath,
    );
  }

  /// Serializes this preset to a JSON-compatible map.
  ///
  /// Used for persistent storage in SharedPreferences.
  Map<String, Object?> toJson() {
    return {
      'id': id,
      'moduleId': moduleId,
      'name': name,
      'params': params,
      'view': {
        'panX': view.pan.x,
        'panY': view.pan.y,
        'zoom': view.zoom,
        'rotX': view.rotation.x,
        'rotY': view.rotation.y,
        'rotZ': view.rotation.z,
      },
      'createdAt': createdAt.toIso8601String(),
      'isBuiltIn': isBuiltIn,
      'thumbnailPath': thumbnailPath,
    };
  }

  /// Deserializes a preset from a JSON map.
  ///
  /// Throws if required fields are missing.
  static FractalPreset fromJson(Map<String, Object?> json) {
    final view = json['view'] as Map<String, Object?>? ?? {};
    return FractalPreset(
      id: json['id'] as String,
      moduleId: json['moduleId'] as String,
      name: json['name'] as String,
      params: _decodePresetParams(json['params'] as Map),
      view: FractalViewState(
        pan: Vector2(
          (view['panX'] as num? ?? 0).toDouble(),
          (view['panY'] as num? ?? 0).toDouble(),
        ),
        zoom: (view['zoom'] as num? ?? 1).toDouble(),
        rotation: Vector3(
          (view['rotX'] as num? ?? 0).toDouble(),
          (view['rotY'] as num? ?? 0).toDouble(),
          (view['rotZ'] as num? ?? 0).toDouble(),
        ),
      ),
      createdAt: DateTime.tryParse(json['createdAt'] as String? ?? '') ??
          DateTime.now(),
      isBuiltIn: json['isBuiltIn'] as bool? ?? false,
      thumbnailPath: json['thumbnailPath'] as String?,
    );
  }

  /// Parses a list of presets from a JSON string.
  ///
  /// Returns an empty list if [payload] is null or empty.
  /// Skips corrupted entries and continues parsing valid ones.
  /// Used for reading from SharedPreferences.
  static List<FractalPreset> listFromPrefs(String? payload) {
    if (payload == null || payload.isEmpty) {
      return [];
    }
    try {
      final decoded = jsonDecode(payload) as List;
      final presets = <FractalPreset>[];
      for (final item in decoded) {
        try {
          final preset =
              FractalPreset.fromJson((item as Map).cast<String, Object?>());
          presets.add(preset);
        } catch (e) {
          // Skip corrupted preset, continue with others
          if (kDebugMode) debugPrint('Failed to parse preset: $e');
        }
      }
      return presets;
    } catch (e) {
      // Corrupted JSON, return empty list
      if (kDebugMode) debugPrint('Failed to parse presets JSON: $e');
      return [];
    }
  }

  /// Serializes a list of presets to a JSON string.
  ///
  /// Used for writing to SharedPreferences.
  static String listToPrefs(List<FractalPreset> presets) {
    return jsonEncode(presets.map((preset) => preset.toJson()).toList());
  }
}

import 'package:vector_math/vector_math.dart';

/// Represents the view/camera state for fractal rendering.
///
/// This class captures the user's navigation state within a fractal:
/// - For 2D fractals: pan offset and zoom level
/// - For 3D fractals: rotation angles and zoom level
///
/// [FractalViewState] is designed to be stored in presets and serialized,
/// allowing users to save and restore specific viewpoints.
///
/// {@category Models}
///
/// Example:
/// ```dart
/// final view = FractalViewState(
///   pan: Vector2(-0.5, 0.2),  // Offset from center
///   zoom: 3.0,                 // 3x magnification
///   rotation: Vector3.zero(), // No rotation (for 2D)
/// );
/// ```
class FractalViewState {
  /// The 2D pan offset from the fractal center.
  ///
  /// For 2D fractals, this determines which part of the complex plane
  /// is visible. Positive X moves right, positive Y moves down.
  ///
  /// Typical range: -3.0 to 3.0 for each axis.
  final Vector2 _pan;

  /// Returns a defensive copy because [Vector2] is mutable.
  Vector2 get pan => Vector2.copy(_pan);

  /// The current zoom/magnification level.
  ///
  /// - Values > 1.0 zoom in (magnify)
  /// - Values < 1.0 zoom out (shrink)
  /// - Value of 1.0 is the default view
  ///
  /// In controller updates, this is typically clamped to [1e-9, 1e12]
  /// to allow deep-zoom workflows.
  final double zoom;

  /// The 3D rotation angles in radians.
  ///
  /// For 3D fractals like Mandelbulb, this controls the camera orientation:
  /// - x: Rotation around the X axis (pitch)
  /// - y: Rotation around the Y axis (yaw)
  /// - z: Rotation around the Z axis (roll)
  ///
  /// For 2D fractals, this is typically [Vector3.zero()].
  final Vector3 _rotation;

  /// Returns a defensive copy because [Vector3] is mutable.
  Vector3 get rotation => Vector3.copy(_rotation);

  /// Creates a [FractalViewState] with specific view parameters.
  ///
  /// All parameters are required to define a complete view state. The supplied
  /// vector instances are copied because [Vector2] and [Vector3] are mutable.
  FractalViewState({
    required Vector2 pan,
    required this.zoom,
    required Vector3 rotation,
  })  : _pan = Vector2.copy(pan),
        _rotation = Vector3.copy(rotation);

  /// Creates the initial/default view state.
  ///
  /// Centers the view with no pan offset, 1x zoom, and no rotation.
  /// This is the starting point when a fractal is first loaded.
  FractalViewState.initial()
      : _pan = Vector2.zero(),
        zoom = 1.0,
        _rotation = Vector3.zero();

  /// Creates a copy of this view state with the given fields replaced.
  ///
  /// Unspecified fields retain their original values.
  ///
  /// Example:
  /// ```dart
  /// final zoomed = view.copyWith(zoom: view.zoom * 2);
  /// ```
  FractalViewState copyWith({
    Vector2? pan,
    double? zoom,
    Vector3? rotation,
  }) {
    return FractalViewState(
      pan: pan ?? _pan,
      zoom: zoom ?? this.zoom,
      rotation: rotation ?? _rotation,
    );
  }
}

